from pyspark.sql.functions import sum, col

def compute_high_volume_groups(df):
    try:
        result = (df
            .groupBy('region', 'customer_type')
            .agg(sum('daily_kw').alias('total_kw'))
            .filter(col('daily_kw') > 5000))
        return result
    except Exception as e:
        print(f'Filter failed: {e}')
        return df.groupBy('region', 'customer_type').agg(sum('daily_kw').alias('total_kw'))

high_volume = compute_high_volume_groups(df)
high_volume.show()
